  tagName: string;
  size?: "sm" | "lg";
};

const { tag, tagName, size = "lg" } = Astro.props;

const locale = Astro.currentLocale ?? config.site.lang;
---

<li>
  <a
    href={getRelativeLocaleUrl(locale, `tags/${tag}/`)}
