    class:list={[
      "flex items-center gap-0.5",
      "border-foreground border-b-2 border-dashed",
      "hover:border-accent hover:text-accent hover:-mt-0.5",
      "focus-visible:text-accent focus-visible:border-none",
      { "text-sm": size === "sm" },
      { "text-lg": size === "lg" },
    ]}
  >
    <IconHash
      class:list={[
        "opacity-80",
        { "size-5": size === "lg" },
        { "size-4": size === "sm" },
      ]}
    />
    {tagName}
  </a>
</li>

