      postIds={relatedPosts.map((post) => post.id)}
    />
  ) : null
}

---
import type { CollectionEntry } from "astro:content";
import IconEdit from "@/assets/icons/IconEdit.svg";
import { useTranslations } from "@/i18n";
import config from "@/config";

type Props = {
  hideEditPost?: CollectionEntry<"posts">["data"]["hideEditPost"];
  class?: string;
  post: CollectionEntry<"posts">;
};

const { hideEditPost, post, class: className = "" } = Astro.props;

const editPost = config.features.editPost;
const href = editPost.enabled ? `${editPost.url}${post.filePath}` : "";
const showEditPost = editPost.enabled && !hideEditPost && href.trim() !== "";

const t = useTranslations(Astro.currentLocale);
---

{
  showEditPost && (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      class:list={[
        "hover:text-accent text-muted-foreground flex justify-baseline gap-1.5",
        className,
      ]}
    >
      <IconEdit class="inline-block" />
      <span>{t.post.editPage}</span>
    </a>
  )
}

---
interface Props {
  href: string;
  size?: "md" | "lg";
  block?: boolean;
  style?: "outline" | "primary" | "inverted" | "muted";
  class?: string;
  [x: string]: any;
}

const {
  href,
  block,
  size = "lg",
  style = "primary",
  class: className,
  ...rest
} = Astro.props;

const sizes = {
  lg: "px-5 py-2.5",
  md: "px-4 py-2",
};

const styles = {
  outline: "bg-white border-2 border-black hover:bg-gray-100 text-black ",
  primary: "bg-black text-white hover:bg-gray-800  border-2 border-transparent",
  inverted: "bg-white text-black   border-2 border-transparent",
  muted: "bg-gray-100 hover:bg-gray-200   border-2 border-transparent",
};
---

<a
  href={href}
  {...rest}
  class:list={[
    "rounded-sm text-center transition focus-visible:ring-2 ring-offset-2 ring-gray-200",
    block && "w-full",
    sizes[size],
    styles[style],
    className,
  ]}
  ><slot />
</a>

---
import type { HTMLTag, Polymorphic } from 'astro/types'

import type { CardList } from '../../types'
import { cn } from '../../utils'

type Props<Tag extends HTMLTag> = Polymorphic<{ as: Tag }> & {
  main?: boolean
  children: CardList
}
const { main = false, children } = Astro.props
---

<ul class={cn('flex flex-col gap-y-1', !main && 'subitem list-disc ms-5')}>
  {
    children.map((child: CardList[number]) => {
      const Tag = child.link ? 'a' : 'p'
      return (
        <li>
          <Tag
            href={child.link}
            class={cn(
              'block',
              main ? 'text-foreground' : 'text-muted-foreground',
              Tag == 'p' && 'mb-2 mt-1'
            )}
          >
            {child.title}
          </Tag>
          {child.children && child.children.length > 0 && <Astro.self children={child.children} />}
        </li>
      )
    })
  }
</ul>

import { getRssString } from '@astrojs/rss';

import { SITE, METADATA, APP_BLOG } from 'astrowind:config';
import { fetchPosts } from '~/utils/blog';
import { getPermalink } from '~/utils/permalinks';

export const GET = async () => {
  if (!APP_BLOG.isEnabled) {
    return new Response(null, {
      status: 404,
      statusText: 'Not found',
    });
  }

  const posts = await fetchPosts();

  const rss = await getRssString({
    title: `${SITE.name}’s Blog`,
    description: METADATA?.description || '',
    site: import.meta.env.SITE,

    items: posts.map((post) => ({
      link: getPermalink(post.permalink, 'post'),
      title: post.title,
      description: post.excerpt,
      pubDate: post.publishDate,
    })),

    trailingSlash: SITE.trailingSlash,
  });

  return new Response(rss, {
    headers: {
      'Content-Type': 'application/xml',
    },
  });
};

---
import IconChevronLeft from "@/assets/icons/IconChevronLeft.svg";
import LinkButton from "@/components/LinkButton.astro";
import { getRelativeLocaleUrl } from "astro:i18n";
import { useTranslations } from "@/i18n";
import config from "@/config";

const locale = Astro.currentLocale ?? config.site.lang;
const t = useTranslations(locale);
---

{
  config.features.showBackButton && (
    <div class="app-layout flex items-center justify-start">
      <LinkButton
        id="back-button"
        href={getRelativeLocaleUrl(locale, "")}
        class="focus-outline hover:text-foreground/75 -ms-2 mt-8 mb-2"
      >
        <IconChevronLeft class="inline-block size-6 rtl:rotate-180" />
        <span>{t.post.goBack}</span>
      </LinkButton>
    </div>
  )
}

<script>
  function updateGoBackUrl() {
    const backButton: HTMLAnchorElement | null =
      document.querySelector("#back-button");

    const backUrl = sessionStorage.getItem("backUrl");

    if (backUrl && backButton) {
      backButton.href = backUrl;
    }
  }

  document.addEventListener("astro:page-load", updateGoBackUrl);
  updateGoBackUrl();
</script>

